func TestPKIToken(t *testing.T) {
	config.Mode = 0
	cert, err := LoadRootCert("../../google_confidential_space_root.crt")
	require.NoError(t, err)

	token, err := ValidatePKIToken(cert, exampleToken)
	require.NoError(t, err)

	ok, err := ValidateClaims(token, []string{})
	// fmt.Println(token.Claims.(*GoogleTeeClaims).EatNonce)
	require.NoError(t, err)
	require.True(t, ok)

	require.Equal(t, "sha256", token.Claims.(*GoogleTeeClaims).SubMods.Container.ImageId[0:6])
	config.Mode = 1
}
